import{_ as e,o as t,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Analytics Overview","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/index.md","filePath":"analytics/index.md"}'),r={name:"analytics/index.md"};function s(l,a,c,o,g,d){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="analytics-overview" tabindex="-1">Analytics Overview <a class="header-anchor" href="#analytics-overview" aria-label="Permalink to &quot;Analytics Overview&quot;">​</a></h1><p>Diamond Analytics turns raw game and practice data into visual analytics that coaches can act on. Analytics are available for all four areas of the game plus mechanics assessments.</p><h2 id="accessing-analytics" tabindex="-1">Accessing Analytics <a class="header-anchor" href="#accessing-analytics" aria-label="Permalink to &quot;Accessing Analytics&quot;">​</a></h2><p>Navigate to <strong>Analytics</strong> from the bottom navigation or More menu. Select a player from the roster to view individual analytics, or view Team Analytics for aggregate stats.</p><h2 id="analytics-types" tabindex="-1">Analytics Types <a class="header-anchor" href="#analytics-types" aria-label="Permalink to &quot;Analytics Types&quot;">​</a></h2><p><strong>Pitching Analytics</strong> — heat maps, velocity trends, pitch type distribution, strikeout and walk rates, ERA</p><p><strong>Hitting Analytics</strong> — spray chart, batting average trend, contact type distribution, hard hit rate, OBP and slugging</p><p><strong>Fielding Analytics</strong> — fielding percentage, zone tendency polar charts, throwing accuracy, error analysis</p><p><strong>Baserunning Analytics</strong> — stolen base percentage, caught stealing rate, per-base breakdown</p><p><strong>Mechanics Assessments</strong> — radar charts for all four mechanics areas with phase breakdowns and trend lines</p><h2 id="event-type-filter" tabindex="-1">Event Type Filter <a class="header-anchor" href="#event-type-filter" aria-label="Permalink to &quot;Event Type Filter&quot;">​</a></h2><p>All analytics screens include an event type filter:</p><ul><li><strong>All</strong> — includes game, scrimmage, team practice, and individual practice data</li><li><strong>Game</strong> — game data only</li><li><strong>Scrimmage</strong> — scrimmage data only</li><li><strong>Team Practice</strong> — practice data only</li><li><strong>Individual Practice</strong> — individual session data only</li></ul><p>Use this filter to compare in-game performance against practice performance.</p><h2 id="date-range-filter" tabindex="-1">Date Range Filter <a class="header-anchor" href="#date-range-filter" aria-label="Permalink to &quot;Date Range Filter&quot;">​</a></h2><p>Filter analytics to a specific date range — useful for evaluating performance over a particular stretch of games or comparing before and after a training intervention.</p><h2 id="minimum-sample-sizes" tabindex="-1">Minimum Sample Sizes <a class="header-anchor" href="#minimum-sample-sizes" aria-label="Permalink to &quot;Minimum Sample Sizes&quot;">​</a></h2><p>Analytics become meaningful with sufficient data. As a general guide:</p><ul><li>Batting average: meaningful after 20+ at-bats</li><li>ERA: meaningful after 10+ innings pitched</li><li>Fielding percentage: meaningful after 20+ fielding chances</li><li>Mechanics assessments: meaningful after 5+ sessions</li></ul>',19)])])}const h=e(r,[["render",s]]);export{m as __pageData,h as default};
